#include <Arduino.h>
#include <M5Unified.h>
#include <BleGamepad.h>
#include <WiFi.h>
#include <M5HatMiniJoyC.h>

// M5Stick-C Hat slot I2C Pins
#define JOYC_SDA 0
#define JOYC_SCL 26

enum ButtonState
{
    UNKNOWN = -1,
    NONE = 0,
    A = 1,
    B = 2,
    UP = 4,
    DOWN = 8,
    LEFT = 16,
    RIGHT = 32,
};

M5HatMiniJoyC joyc; // Joystick object
BleGamepad bleGamepad("M5MiniJoyC Gamepad", "davevw.com", 100);
BleGamepadConfiguration bleGamepadConfig;
ButtonState lastState = ButtonState::UNKNOWN;

static void waitMiniJoyCReady() // from https://github.com/m5stack/StackChan/blob/main/remote/code/main/StackChan-RemoteControl-ESPNow.cpp
{
    while (!joyc.begin(&Wire, MiniJoyC_ADDR, JOYC_SDA, JOYC_SCL,
                       100000UL))
    {
        delay(100); // Retry every 100ms
    }
}

